<script setup>
import { ref, computed, onMounted, watch } from 'vue'
import { Search, Filter, LayoutGrid, List, X, Bell, Bookmark, UserCircle } from 'lucide-vue-next'
import { useRoute, useRouter } from 'vue-router'
import TenderCard from '../components/TenderCard.vue'
import { useAuthStore } from '../stores/auth'

const authStore = useAuthStore()

const route = useRoute()
const router = useRouter()
const isSessionExpired = ref(false)
const searchQuery = ref('')

const refetchSession = async () => {
   // Try to bounce the session
   isLoading.value = true;
   isSessionExpired.value = false;
   await authStore.logout(false); // Clean logout
   router.push('/login?redirect=' + route.fullPath);
}
const viewMode = ref('grid') 
const priceRange = ref(5000000)
const sortBy = ref('Deadline (Soonest)')

// Filters
const selectedCategory = ref('All')
const selectedStatus = ref('All')
const selectedPriority = ref('All')
const liveBiddingOnly = ref(false)

const tenders = ref([])
const isLoading = ref(true)
const totalSavedCount = ref(0)

const fetchTotalSavedCount = async () => {
  if (!authStore.isAuthenticated) return;
  try {
    const response = await authStore.secureFetch('/api/method/supplier_portal.api.count_saved_tenders');
    const result = await response.json();
    
    if (result.message !== undefined) {
      totalSavedCount.value = result.message;
    }
  } catch (error) {
    console.error("Error updating saved count:", error);
  }
}
const createAlert = () => {
    // 1. Reference the global frappe object
    const frappe = window.frappe;

    if (!frappe || !frappe.ui || !frappe.ui.Dialog) {
        console.error("Frappe UI Dialog is not available.");
        return;
    }

    // Fallback for translation function if window.__ is missing
    const _t = window.__ || ((s) => s);

    const d = new frappe.ui.Dialog({
        title: _t('Set Tender Alert'),
        fields: [
            {
                label: _t('Alert Name'),
                fieldname: 'alert_name',
                fieldtype: 'Data',
                placeholder: 'e.g., Raw Materials Tenders',
                reqd: 1
            },
            {
                label: _t('Categories'),
                fieldname: 'categories',
                fieldtype: 'MultiSelectPills',
                // Updated to use dynamic categories if available, otherwise fallback
                options: categories.value.map(c => c.name).filter(n => n !== 'All'),
                reqd: 1
            },
            { fieldtype: 'Section Break', label: _t('Budget Range') },
            {
                label: _t('Min Budget (₹)'),
                fieldname: 'budget_min',
                fieldtype: 'Currency',
                default: 0.00
            },
            {
                label: _t('Max Budget (₹)'),
                fieldname: 'budget_max',
                fieldtype: 'Currency',
                placeholder: '5.0Cr'
            },
            { fieldtype: 'Section Break' },
            {
                label: _t('Keywords (Optional)'),
                fieldname: 'keywords',
                fieldtype: 'Small Text',
                placeholder: 'e.g., steel, pipes, valves'
            },
            { fieldtype: 'Section Break', label: _t('Notification Channels') },
            { label: _t('Email Notifications'), fieldname: 'email_notif', fieldtype: 'Check', default: 1 },
            { label: _t('Push Notifications'), fieldname: 'push_notif', fieldtype: 'Check', default: 1 },
            {
                label: _t('Alert Frequency'),
                fieldname: 'frequency',
                fieldtype: 'Select',
                options: ['Instant', 'Daily', 'Weekly'],
                default: 'Instant'
            }
        ],
        primary_action_label: _t('Create Alert'),
        primary_action(values) {
            frappe.call({
                method: "supplier_portal.api.create_tender_alert", 
                args: {
                    payload: values
                },
                callback: (r) => {
                    if (!r.exc) {
                        frappe.show_alert({
                            message: _t('Alert Created Successfully'), 
                            indicator: 'green'
                        });
                        d.hide();
                    }
                }
            });
        },
        secondary_action_label: _t('Cancel'),
        secondary_action() {
            d.hide();
        }
    });

    d.show();
};

const showAlertModal = ref(false);

const alertForm = ref({
  alert_name: '',
  selected_categories: [], 
  channels: {
    email: true,
    push: true,
    sms: false
  },
  frequency: 'Instant'
});

const openAlertModal = () => {
  alertForm.value = {
    alert_name: '',
    selected_categories: [], 
    budget_max: 50000000,
    keywords: '',
    channels: { email: true, push: true, sms: false },
    frequency: 'Instant'
  };
  showAlertModal.value = true;
};

const toggleCategory = (catName) => {
  const index = alertForm.value.selected_categories.indexOf(catName);
  if (index > -1) {
    alertForm.value.selected_categories.splice(index, 1);
  } else {
    alertForm.value.selected_categories.push(catName);
  }
};
const getCookie = (name) => {
  const value = `; ${document.cookie}`;
  const parts = value.split(`; ${name}=`);
  if (parts.length === 2) return decodeURIComponent(parts.pop().split(';').shift());
  return null;
};

const submitAlert = async () => {
  if (!alertForm.value.alert_name) {
    alert("Please provide an alert name");
    return;
  }

  try {
    const response = await authStore.secureFetch('/api/method/supplier_portal.api.create_tender_alert', {
      method: 'POST',
      body: JSON.stringify({ payload: alertForm.value })
    });
    
    const result = await response.json();
    
    if (result.message) {
      showAlertModal.value = false;
      window.dispatchEvent(new CustomEvent('notification-updated'));
      alert("Tender alert created successfully!");
    }
  } catch (error) {
    console.error("Submission failed:", error);
  }
};

const notifications = ref([]);
const loading = ref(false);

const fetchNotifications = async () => {
  loading.value = true;
  try {
    const response = await fetch('/api/method/supplier_portal.api.get_my_notifications');
    const data = await response.json();
    notifications.value = data.message || [];
  } catch (error) {
    console.error("Error fetching notifications:", error);
  } finally {
    loading.value = false;
  }
};

onMounted(() => {
  fetchNotifications();
});

const getPriorityActiveClasses = (priority) => {
   const mapping = {
      'Urgent': 'bg-red-50 text-red-700 border-red-200 ring-1 ring-red-200',
      'High': 'bg-orange-50 text-orange-700 border-orange-200 ring-1 ring-orange-200',
      'Normal': 'bg-blue-50 text-blue-700 border-blue-200 ring-1 ring-blue-200',
      'Low': 'bg-gray-50 text-gray-700 border-gray-200 ring-1 ring-gray-200',
      'All': 'bg-indigo-50 text-indigo-700 border-indigo-200 ring-1 ring-indigo-200'
   }
   return mapping[priority] || mapping['All']
}

const getPriorityDotClass = (priority) => {
   const mapping = {
      'Urgent': 'bg-red-500',
      'High': 'bg-orange-500',
      'Normal': 'bg-blue-500',
      'Low': 'bg-gray-400'
   }
   return mapping[priority] || 'bg-transparent'
}

const fetchTenders = async () => {
  isLoading.value = true
  try {
    // 1. Define the plain object first
    const queryArgs = { 
      limit: 20,
      offset: 0 
    }

    // 2. Add priority only if it's not 'All'
    if (selectedPriority.value !== 'All') {
      queryArgs.priority = selectedPriority.value
    }

    // 3. Convert the object to Search Params
    const params = new URLSearchParams(queryArgs)

    // 4. Use the params in the fetch call
    const response = await authStore.secureFetch(`/api/method/supplier_portal.api.get_active_tenders?${params.toString()}`)

    if (!response.ok) {
        if (response.status === 403 || response.status === 401) {
            isSessionExpired.value = true;
            return;
        }
        throw new Error(`HTTP Error: ${response.status}`);
    }

    const result = await response.json()
    const data = result.message || []
    
    tenders.value = data.map(rfq => ({
      id: rfq.name,                               
      title: rfq.custom_rfq_subject || rfq.name,               
      description: rfq.custom_rfq_description ? rfq.custom_rfq_description.replace(/<[^>]*>?/gm, '') : '', 
      category: rfq.custom_rfq_category,        
      status: rfq.custom_bid_status,             
      budget: parseFloat(rfq.custom_total_budget_) || 0, 
      deadline: rfq.custom_bid_submission_last_date,             
      publishedDate: rfq.custom_publish_date,
      priority: rfq.custom_priority,
      liveBidding: rfq.custom_bid_status === 'Active' && !!rfq.custom_enable_live_bidding
    }))
  } catch (error) {
    console.error("Failed to load tenders:", error)
    tenders.value = [] 
  } finally {
    isLoading.value = false
  }
}

watch([selectedPriority, selectedCategory], () => {
  fetchTenders();
})

onMounted(() => {
   fetchTenders();
   fetchTotalSavedCount();
   if (route.query.category) {
      selectedCategory.value = route.query.category
   }
})


const categories = computed(() => {
  const counts = {} // { 'Raw Materials': 2, ... }
  tenders.value.forEach(t => {
      const cat = t.category || 'Uncategorized';
      counts[cat] = (counts[cat] || 0) + 1;
  })

  // Basic list from counts
  const list = Object.keys(counts).map(name => ({
      name: name,
      count: counts[name]
  }));

  // Add 'All' or ensure known categories are present? 
  // For now let's just list what is available + 'All'
  // Or keep the predefined list for UI structure but update counts?
  // Let's go with dynamic list to avoid "hard coded data" complaint strictly.
  
  const allCount = tenders.value.length;
  // Prepend All
  return [{ name: 'All', count: allCount }, ...list];
})

const statuses = ['All', 'Active', 'Closing Soon', 'Closed']
const priorities = ['All', 'Urgent', 'High', 'Normal', 'Low']

// Mock Data

const filteredTenders = computed(() => {
  let result = tenders.value.filter(tender => {
    const matchesSearch = tender.title.toLowerCase().includes(searchQuery.value.toLowerCase()) || 
                          tender.id.toLowerCase().includes(searchQuery.value.toLowerCase())
    const matchesStatus = selectedStatus.value === 'All' || tender.status === selectedStatus.value
    const matchesBudget = tender.budget <= priceRange.value
    const matchesLive = !liveBiddingOnly.value || tender.liveBidding
    
    return matchesSearch && matchesStatus && matchesBudget && matchesLive
  })

  // Sorting
  return result.sort((a, b) => {
    switch (sortBy.value) {
      case 'Deadline (Soonest)':
        return new Date(a.deadline) - new Date(b.deadline)
      case 'Deadline (Latest)':
        return new Date(b.deadline) - new Date(a.deadline)
      case 'Budget (Low to High)':
        return a.budget - b.budget
      case 'Budget (High to Low)':
        return b.budget - a.budget
      case 'Most Bids':
        return b.bids - a.bids
      default:
        // Recently Added (simulated by ID desc)
        return b.id.localeCompare(a.id)
    }
  })
})

const clearFilters = () => {
   selectedCategory.value = 'All'
   selectedStatus.value = 'All'
   selectedPriority.value = 'All'
   liveBiddingOnly.value = false
   searchQuery.value = ''
   priceRange.value = 20000000
}
</script>

<template>
  <div class="mx-auto max-w-7xl px-4 sm:px-6 lg:px-8 py-8">
     <!-- Page Header -->
    <div class="flex flex-col md:flex-row md:items-center md:justify-between mb-8">
      <div>
        <h1 class="text-3xl font-bold tracking-tight text-gray-900">Active Tenders</h1>
        <p class="mt-1 text-sm text-gray-500">{{ filteredTenders.length }} active tenders • 1 closing soon</p>
      </div>
